INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24015, 0.0, "カオリ（サマー）", 10021, 24, 4, 1, "2030/12/17 14:59:59", 0.0, 0.0, 4, "2019/07/31 12:00:00", "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24016, 4.0, "カオリ（サマー）", 10021, 24, 4, 2, "2030/12/17 14:59:59", 0.0, 0.0, 1, "2019/07/31 12:00:00", "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24017, 0.0, "カオリ（サマー）", 10021, 24, 4, 3, "2030/12/17 14:59:59", 0.0, 0.0, 4, "2019/07/31 12:00:00", "マジムンだらけで目が回るさ～！\nふらふらさ～！");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24018, 5.2, "カオリ（サマー）", 10021, 24, 1, 4, "2030/12/17 14:59:59", 0.0, 0.0, 2, "2019/07/31 12:00:00", "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24019, 4.2, "カオリ（サマー）", 10021, 24, 5, 5, "2030/12/17 14:59:59", 0.0, 0.0, 6, "2019/07/31 12:00:00", "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24020, 0.0, "カオリ（サマー）", 10021, 24, 2, 6, "2030/12/17 14:59:59", 0.0, 0.0, 2, "2019/07/31 12:00:00", "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24021, 6.4, "カオリ（サマー）", 10021, 24, 1, 7, "2030/12/17 14:59:59", 0.0, 0.0, 6, "2019/07/31 12:00:00", "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24022, 0.0, "カオリ（サマー）", 10021, 24, 2, 8, "2030/12/17 14:59:59", 0.0, 0.0, 2, "2019/07/31 12:00:00", "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24023, 10.08, "カオリ（サマー）", 10021, 24, 6, 9, "2030/12/17 14:59:59", 0.0, 0.0, 3, "2019/07/31 12:00:00", "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24024, 5.0, "カオリ（サマー）", 10021, 24, 1, 10, "2030/12/17 14:59:59", 0.0, 0.0, 2, "2019/07/31 12:00:00", "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪");
INSERT INTO `v1_2724629361527c33abafc78a85259714901ebf842f98b619997f88a383e845ab` VALUES (110501, 24025, 0.0, "カオリ（サマー）", 10021, 24, 2, 11, "2030/12/17 14:59:59", 0.0, 0.0, 2, "2019/07/31 12:00:00", "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！");
